-    /// Parse Python mode string
-    pub fn parse(mode: []const u8) !IOMode {
-        var result = IOMode{};
-
-        for (mode) |c| {
-            switch (c) {
-                'r' => result.read = true,
-                'w' => {
-                    result.write = true;
-                    result.create = true;
-                    result.truncate = true;
-                },
-                'a' => {
-                    result.append = true;
-                    result.create = true;
-                },
-                'x' => {
-                    result.write = true;
-                    result.create = true;
-                    result.exclusive = true;
-                },
-                'b' => {
-                    result.binary = true;
-                    result.text = false;
-                },
-                't' => result.text = true,
-                '+' => result.update = true,
-                else => return error.InvalidMode,
-            }
-        }
-
-        // Default to read if no mode specified
-        if (!result.read and !result.write and !result.append) {
-            result.read = true;
-        }
-
-        // Update mode adds read capability
-        if (result.update) {
-            result.read = true;
-            if (!result.write and !result.append) {
